	staleWhileRevalidate?: boolean;
	/**
	 * Number of retry attempts after a failed fetch.
	 */
	maxRetries?: number;
	/**
	 * Delay (in ms) between retry attempts.
	 */
	retryDelay?: number;
	/**
	 * Controls how `retryDelay` grows between attempts. Defaults to 'linear'.
