describe('autocomplete with async options', () => {
	let input: MockReadable;
	let output: MockWritable;
	const testOptions = [
		{ value: 'apple', label: 'Apple' },
		{ value: 'banana', label: 'Banana' },
		{ value: 'cherry', label: 'Cherry' },
	];

	beforeEach(() => {
		input = new MockReadable();
		output = new MockWritable();
		vi.useFakeTimers();
	});

	afterEach(() => {
		vi.useRealTimers();
		vi.restoreAllMocks();
	});

	test('shows the loading message while an async fetch is in flight', async () => {
		const fetchFn = vi.fn(
			(search: string) =>
				new Promise<typeof testOptions>((resolve) => {
					setTimeout(
						() => resolve(testOptions.filter((o) => o.label.toLowerCase().includes(search))),
						50
					);
				})
		);

		const result = autocomplete({
			message: 'Select a fruit',
			options: fetchFn,
			input,
			output,
			loadingMessage: 'Fetching fruits...',
			debounceMs: 0,
		});

		await vi.advanceTimersByTimeAsync(10);
		expect(output.buffer.join('')).toContain('Fetching fruits...');

		await vi.advanceTimersByTimeAsync(50);
		input.emit('keypress', '', { name: 'return' });
		await result;
	});

	test('shows a custom no-results message', async () => {
		const fetchFn = vi.fn(async () => []);

		const result = autocomplete({
			message: 'Select a fruit',
			options: fetchFn,
			input,
			output,
			noResultsMessage: 'Nothing here',
			debounceMs: 0,
		});

		await vi.runAllTimersAsync();
		input.emit('keypress', 'z', { name: 'z' });
		await vi.runAllTimersAsync();

		expect(output.buffer.join('')).toContain('Nothing here');

		input.emit('keypress', '', { name: 'return' });
		await result;
	});

	test('shows the "type at least N characters" message when input is too short', async () => {
		const fetchFn = vi.fn(async (search: string) =>
			testOptions.filter((o) => o.label.toLowerCase().includes(search))
		);

		const result = autocomplete({
			message: 'Select a fruit',
			options: fetchFn,
			input,
			output,
			minSearchLength: 3,
			debounceMs: 0,
		});

		await vi.runAllTimersAsync();
		input.emit('keypress', 'a', { name: 'a' });
		await vi.runAllTimersAsync();

		expect(output.buffer.join('')).toContain('Type at least 3 characters');

		input.emit('keypress', '', { name: 'return' });
		await result;
	});

	test('shows the fetch error message when the resolver rejects', async () => {
		const fetchFn = vi.fn(async () => {
			throw new Error('boom');
		});

		const result = autocomplete({
			message: 'Select a fruit',
			options: fetchFn,
			input,
			output,
			debounceMs: 0,
		});

		await vi.runAllTimersAsync();

		expect(output.buffer.join('')).toContain('boom');

		input.emit('keypress', '', { name: 'return' });
		await result;
	});
});

